21. function runNodeScript(scriptName, args) {
22.   const scriptPath = path.join(ROOT_DIR, 'eval', 'scripts', scriptName);
23.   const result = runCommand(process.execPath, [scriptPath, ...args], { cwd: ROOT_DIR });
24.   if (!result.ok) {
25.     throw new Error(
26.       [
27.         `Script failed: ${scriptName}`,
28.         `exitCode=${result.status ?? 'unknown'} signal=${result.signal ?? 'none'}`,
29.         `stdout:\n${truncateText(result.stdout || '<empty>', 4000)}`,
30.         `stderr:\n${truncateText(result.stderr || '<empty>', 4000)}`
31.       ].join('\n')
32.     );
33.   }
34.   return parseCommandJsonOutput(result, `Script ${scriptName}`);
35. }
