23. function deriveObservedUsage(artifactSummary) {
24.   const rawCandidates = artifactSummary.usageCandidates ?? [];
25.   const normalized = [];
26.   for (const candidate of rawCandidates) {
27.     const value = candidate.value;
28.     if (!value || typeof value !== 'object') continue;
29.     const promptTokens = value.promptTokens ?? value.prompt_tokens ?? value.inputTokens ?? value.input_tokens ?? value.input ?? null;
30.     const completionTokens = value.completionTokens ?? value.completion_tokens ?? value.outputTokens ?? value.output_tokens ?? value.output ?? null;
31.     const totalTokens = value.totalTokens ?? value.total_tokens ?? value.total ?? null;
32.     if ([promptTokens, completionTokens, totalTokens].some((entry) => typeof entry === 'number')) {
33.       normalized.push({
34.         path: candidate.path,
35.         promptTokens,
36.         completionTokens,
37.         totalTokens: totalTokens ?? [promptTokens, completionTokens].filter((entry) => typeof entry === 'number').reduce((sum, entry) => sum + entry, 0)
38.       });
39.     }
40.   }
